INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 5, 1033501, 1033501043, 1, 0, 1, "オラの食材とあんちゃんの腕……\nこれは二人の共同作業ってことに……\nな、なんでもねぇ！\n気にしねぇでけろ！", "", 103311, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1033501, 1033501044, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1033501, 1033501045, "", "", 0, "vo_adv_1033501_002", "", "vo_adv_1033501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 6, 1033501, 1033501046, 1, 0, 1, "それにしても食べるのが\nもったいねぇいいケーキだなぁ……\nでも食べなきゃ食べねぇで\nもったいねぇよなぁ……", "", 103311, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1033501, 1033501047, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1033501, 1033501048, "", "", 0, "vo_adv_1033501_003", "", "vo_adv_1033501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 6, 1033501, 1033501049, 1, 0, 1, "うーん……\nオラ一人で食べるのも申し訳ねぇし\nエリザベスパークのみんなで\n食べるべか！", "", 103311, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1033501, 1033501050, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1033501, 1033501051, "", "", 0, "vo_adv_1033501_004", "", "vo_adv_1033501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 6, 1033501, 1033501052, 1, 0, 1, "みんなで過ごすのがオラにとって\n最高の誕生日だべ！\nあんがとな、あんちゃん！", "", 103311, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1033501, 1033501053, "", "", "", "", "", 0, "");
