INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (13, "", 1034501, 1034501039, "", "", "", 870, "", 103411, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 4, 1034501, 1034501040, 1, 0, 1, "わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！", "", 103411, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1034501, 1034501041, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1034501, 1034501042, "", "", 0, "vo_adv_1034501_001", "", "vo_adv_1034501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 6, 1034501, 1034501043, 1, 0, 1, "麦しゅわに合わないかも……って、\nそんな気を使わなくていいわよ。\nだって、今日は飲むつもりはないもの。", "", 103411, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1034501, 1034501044, "", "", "", "", "", 0, "");
