INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 5, 1034501, 1034501046, 1, 0, 1, "なんでって、それは……\nキミがお祝いに来てくれるかも、\nなんて思ってたから……", "", 103411, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1034501, 1034501047, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1034501, 1034501048, "", "", 0, "vo_adv_1034501_003", "", "vo_adv_1034501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 5, 1034501, 1034501049, 1, 0, 1, "だから、今日は麦しゅわは封印よ。\n麦しゅわもありの大人な誕生日は、\nキミが大人になってから……ね？", "", 103411, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1034501, 1034501050, "", "", "", "", "", 0, "");
