INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 7, 1051501, 1051501040, 1, 0, 1, "誕生日を祝ってくれてありがとう。\nいくつになってもお祝いして\nもらえるのはうれしいものね。", "", 105111, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1051501, 1051501041, "", "", "", "", "", 0, "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (21, 0, 1051501, 1051501042, "", "", 0, "vo_adv_1051501_001", "", "vo_adv_1051501", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 4, 1051501, 1051501043, 1, 0, 1, "え、このケーキ君の手作りなの？\nなによ至れり尽くせりじゃない。", "", 105111, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1051501, 1051501044, "", "", "", "", "", 0, "");
