INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (11, 6, 1051501, 1051501046, 1, 0, 1, "ここまでしてもらったら大人しく\n祝ってもらうしかないわね。\nいくら私でも時と場合は\nちゃんとわきまえるわよ。", "", 105111, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (91, "", 1051501, 1051501047, "", "", "", "", "", 0, "");
